1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	
57	const BASE_PREMIUM: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: 25,
63	  moonstone: 25,
64	};
65	
66	const CURSED_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_THRESHOLD = 5;
68	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
69	
70	const itemBasePremium = (item: Item): number => {
71	  const base = BASE_PREMIUM[item.type] ?? 0;
72	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
73	  const highEnchantmentSurcharge =
74	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
75	  return base + cursedSurcharge + highEnchantmentSurcharge;
76	};
77	
78	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
79	const BLOCK_SIZE = 3;
80	const BLOCK_PREMIUM = 60;
81	
82	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
83	
84	const sumBasePremiums = (items: Item[]): number =>
85	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
86	
87	const groupByType = (items: Item[]): Item[][] => {
88	  const byType = new Map<string, Item[]>();
89	  for (const item of items) {
90	    const group = byType.get(item.type) ?? [];
91	    group.push(item);
92	    byType.set(item.type, group);
93	  }
94	  return [...byType.values()];
95	};
96	
97	const groupPremium = (group: Item[]): number =>
98	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumBasePremiums(group);
99	
100	const componentsPremium = (components: Item[]): number =>
101	  groupByType(components).reduce((total, group) => total + groupPremium(group), 0);
102	
103	const itemsBasePremium = (items: Item[]): number =>
104	  componentsPremium(items.filter(isComponent)) +
105	  sumBasePremiums(items.filter((item) => !isComponent(item)));
106	
107	const quotePremium = (items: Item[]): number =>
108	  itemsBasePremium(items) + PROCESSING_FEE;
109	
110	export const runScenario = (scenario: Scenario): ScenarioResult => {
111	  const results = scenario.steps.map((step): StepResult => {
112	    if (step.op === "quote") {
113	      return { premium: quotePremium(step.items) };
114	    }
115	    return { payout: 0, remainingCap: 0 };
116	  });
117	  return { results };
118	};
