  const base = BASE_PREMIUM[item.type] ?? 0;
  const surcharges = SURCHARGE_RULES
    .filter((rule) => rule.applies(item))
    .reduce((total, rule) => total + base * rule.rate, 0);
  return base + surcharges;
};

